import * as React from "react";
import type { HeadFC, PageProps } from "gatsby";
import styled from "styled-components";
import "../styles/global.css";
import {
  FiMail,
  FiPhone,
  FiGithub,
  FiLinkedin,
  FiDownload,
} from "react-icons/fi";
import {
  FaPython,
  FaJs,
  FaReact,
  FaGitAlt,
  FaNodeJs,
  FaFigma,
  FaGithub,
  FaGitlab,
  FaDocker,
} from "react-icons/fa";
import { SiTypescript, SiDjango, SiPrisma } from "react-icons/si";
import { TbBrandMongodb, TbBrandReactNative } from "react-icons/tb";
import { RiNextjsFill } from "react-icons/ri";

const data = {
  email: "mateusz.zebala.pl@gmail.com",
  phone: "+48 662 961 751",
  github: "https://github.com/mateuszzebala",
  linkedin: "https://www.linkedin.com/in/mateusz-zebala/",
  cv: "/MateuszZebala.pdf",
};

const StyledMain = styled.main`
  background-color: #0f0f0f;
  height: 100vh;
  display: flex;
  flex-direction: row;
  scroll-snap-type: y mandatory;
  align-items: center;
  scroll-behavior: smooth;
  justify-content: space-evenly;
  @media (max-width: 600px) {
    & {
      flex-direction: column;
      height: 200vh;
    }
    & > {
      scroll-snap-align: center;
      width: 100%;
    }
  }
`;

const LeftSide = styled.div`
  display: flex;
  min-height: 100vh;
  flex-direction: column;
  scroll-snap-align: center;
  gap: 40px;
  align-items: center;
  justify-content: center;
  h1,
  h2 {
    color: white;
    font-family: "Montserrat";
    margin: 0;
  }
  h1 {
    font-size: 2rem;
  }
  h2 {
    font-size: 1.2rem;
    font-weight: 300;
  }
  img {
    width: 250px;
    border-radius: 20%;
  }
  .technologies {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 15px;
    flex-direction: row;
    color: white;
    font-size: 24px;
  }
`;

const RightSide = styled.div`
  display: flex;
  min-height: 100vh;
  scroll-snap-align: center;
  flex-direction: column;
  align-items: flex-start;
  justify-content: center;
  gap: 20px;

  a {
    color: white;
    font-family: "Montserrat";
    text-decoration: none;
    display: inline-flex;
    gap: 10px;
    font-size: 20px;
    align-items: center;
    transition: transform 0.2s, color 0.2s;
    svg {
      font-size: 20px;
    }
  }

  a:hover {
    transform: translateX(10px);
    color: grey;
  }
`;

const IndexPage: React.FC<PageProps> = () => {
  return (
    <StyledMain>
      <LeftSide>
        <h1>Mateusz Zębala</h1>
        <h2>Junior Software Developer</h2>
        <img src={"/me.jpeg"} />
        <span className="technologies">
          <span title="Python">
            <FaPython />
          </span>
          <span title="JavaScript">
            <FaJs />
          </span>
          <span title="TypeScript">
            <SiTypescript />
          </span>
          <span title="React">
            <FaReact />
          </span>
          <span title="Git">
            <FaGitAlt />
          </span>
          <span title="Django">
            <SiDjango />
          </span>
          <span title="NodeJS">
            <FaNodeJs />
          </span>
          <span title="Figma">
            <FaFigma />
          </span>
          <span title="Docker">
            <FaDocker />
          </span>
          <span title="MongoDB">
            <TbBrandMongodb />
          </span>
          <span title="React Native">
            <TbBrandReactNative />
          </span>
          <span title="NextJS">
            <RiNextjsFill />
          </span>
          <span title="Prisma">
            <SiPrisma />
          </span>
          <span title="Github">
            <FaGithub />
          </span>
          <span title="Gitlab">
            <FaGitlab />
          </span>
        </span>
      </LeftSide>
      <RightSide>
        <a target="_blank" href={`mailto:${data.email}`}>
          <FiMail /> {data.email}
        </a>
        <a target="_blank" href={`tel:${data.phone.replaceAll(" ", "")}`}>
          <FiPhone /> {data.phone}
        </a>
        <a target="_blank" href={data.linkedin}>
          <FiLinkedin /> Linkedin
        </a>
        <a target="_blank" href={data.github}>
          <FiGithub /> Github
        </a>
        <a target="_blank" href={data.cv} download={"Mateusz-Zebala-CV.pdf"}>
          <FiDownload /> Download CV
        </a>
      </RightSide>
    </StyledMain>
  );
};

export default IndexPage;

export const Head: HeadFC = () => (
  <>
    <title>Mateusz Zębala - Junior Software Developer</title>
    <meta
      name="description"
      content="Junior Software Developer, Poland, Cracow, I am an independent, ambitious, and determinedindividual committed to achieving set goals. I havebeen involved in programming for about 5 years. Ipossess a considerable amount of knowledge and astrong desire to continually acquire new skills. I amopen to new challenges and prepared to dedicate timeand energy to effectively fulfill assignedresponsibilities. I have been tutoring programming forover a year, teaching mainly JavaScript and Python."
    />
    <meta
      name="keywords"
      content="Python, JavaScript, TypeScript, React, Redux, Django, Flask, Git, Github, MongoDB, MySQL, Docker"
    />
    <meta name="author" content="Mateusz Zębala" />
  </>
);
